arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // .NET 9 breaking change: empty environment variables are no longer
        // treated as unset. GetEnvironmentVariable now returns "" instead of
        // null for `export MY_FLAG=""`, so we can properly distinguish
        // "not set" (null) from "explicitly empty" ("").
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly empty");
        }
        else
        {
            Console.WriteLine($"MY_FLAG = {val}");
        }
    }
}

